class User:
    def __init__(self, username, role):
        self.username = username
        self.role = role

class Resource:
    def __init__(self, name, required_permission):
        self.name = name
        self.required_permission = required_permission

# Define role-permission mappings
ROLE_PERMISSIONS = {
    'admin': ['read', 'write', 'delete', 'execute'],
    'manager': ['read', 'write', 'execute'],
    'employee': ['read', 'execute'],
    'guest': ['read']
}

def check_permission(user, resource, operation):
    """Check if user has required permission for resource operation"""
    if user.role not in ROLE_PERMISSIONS:
        return False

    allowed_ops = ROLE_PERMISSIONS[user.role]
    return operation in allowed_ops and operation == resource.required_permission

# Example usage
user1 = User("john", "manager")
file_resource = Resource("report.txt", "read")

if check_permission(user1, file_resource, "read"):
    print(f"Access granted: {user1.username} can read {file_resource.name}")
else:
    print("Access denied")

#include <stdio.h>
#include <unistd.h>

// User mode function - runs with limited privileges
void userModeFunction() {
    printf("Running in USER mode\n");
    // Can only access own memory space
    // Cannot directly access hardware
}

// System call wrapper - triggers kernel mode transition
int protectedOperation(char *filename) {
    // This triggers a system call
    // CPU switches from user to kernel mode
    // Kernel performs the privileged operation
    return open(filename, O_RDONLY);
}

int main() {
    userModeFunction();

    // System call transitions to kernel mode
    int fd = protectedOperation("test.txt");

    if (fd >= 0) {
        printf("File opened via system call\n");
        close(fd);
    }

    return 0;
}
